  ('pukao-6e11b43e-moex-00160', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於行政機關管轄權之敘述，下列何者正確？', '["數機關就同一事件均有管轄權者，即由共同上級機關指定管轄", "依據管轄法定原則，管轄權之更動應依法規或依行政契約為之", "依據管轄法定原則，管轄權僅能依據法律定之", "關於不動產事件，不能依行政程序法第11條定土地管轄時，依不動產所在地定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00161', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '國稅之稽徵屬財政部所屬國稅局之職務權限，學理上稱為何種管轄？', '["事物管轄", "土地管轄", "層級管轄", "功能管轄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00162', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於公務人員之年終考績獎懲，下列敘述何者錯誤？', '["公務員考績受列甲等，晉本俸一級，並給與1個月俸給總額之一次獎金", "公務員考績受列乙等，晉本俸一級，並給與半個月俸給總額之一次獎金", "公務員考績受列丙等，晉本俸一級，無額外獎金", "公務員考績受列丁等，受免職處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00163', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於公務員懲戒之敘述，下列何者為錯誤？', '["公務員懲戒程序為一級二審制", "公務員因同一行為已受懲戒，即不再受懲處", "同一違法行為經法院判決確定其刑事責任後，仍得再予以懲戒", "政務人員之懲戒處分，只適用撤職與申誡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00164', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於公務人員服從義務之敘述，下列何者正確？', '["主管長官與兼管長官同時所發命令不同時，公務人員應向共同上級長官報告", "公務人員對於長官所發命令之合法性如有疑義，得隨時陳述，但無報告義務", "公務人員對於長官所發之命令有絕對服從義務", "長官所發命令有違反刑事法律者，公務員無服從之義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00165', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '依行政執行法規定，義務人經命其提供相當擔保，限期履行，屆期不履行亦未提供相當擔保，於下列 何種情形得聲請法院裁定拘提？', '["顯有逃匿之虞", "顯有履行義務之可能，故意不履行", "就應供強制執行之財產有隱匿或處分之情事", "經命其報告財產狀況，不為報告或為虛偽之報告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00166', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於公務人員保障法規定之調處程序，下列敘述何者正確？', '["復審人、再申訴人之代理人應提出經特別委任之授權證明，始得參與調處", "復審人、再申訴人及有關機關，無正當理由，於指定期日不到場者，視為調處不成立，不得另定調 處期日", "於多數人共同提起保障事件之調處，多數人之代表人須徵得全體復審人或再申訴人過半數之書面同 意為之", "保障事件審理中，公務人員保障暨培訓委員會僅得依申請而進行調處"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00167', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '下列何者非屬公務員服務法適用之對象？', '["未兼行政職之中央研究院研究員", "台糖公司資產營運處處長", "國防部軍醫局副局長", "新北市政府財政局主任秘書"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00168', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '依法應迴避之公務員而未迴避所作成之行政處分其效力為何？', '["效力未定", "得廢止", "得撤銷", "無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL)
